// Map pathname to post ID
const routeToPostId = {
  '/': 23,
  '/about': 31,
  '/service': 32,
  '/project': 36,
  '/contact': 48,
}

// Track current injected style element
let currentStyleEl = null

export function injectPageCss(pathname) {
  const path = pathname.replace(/\/$/, '') || '/'
  const postId = routeToPostId[path]
  if (!postId) return

  // Remove previous page CSS
  if (currentStyleEl && currentStyleEl.parentNode) {
    currentStyleEl.parentNode.removeChild(currentStyleEl)
  }

  // Inject kit CSS (once)
  if (!document.getElementById('elementor-kit-css')) {
    const kitEl = document.createElement('style')
    kitEl.id = 'elementor-kit-css'
    kitEl.textContent = kitCss
    document.head.appendChild(kitEl)
  }

  // Inject page-specific CSS
  const css = pageCss[postId]
  if (css) {
    const el = document.createElement('style')
    el.id = 'elementor-page-css'
    el.textContent = css
    document.head.appendChild(el)
    currentStyleEl = el
  }
}
